import axios from "axios";
import initApp, { Space3DURL } from "../utility/initApp.js";

class Api3DxService {
  constructor(path = "", option = {}) {
    this.path = path;
    this.option = option;
  }

  async get() {
    return this.execute("GET", this.path, "", this.option);
  }

  async post(data) {
    const csrf = await getCSRF();
    return this.execute("POST", this.path, csrf, this.option, data);
  }

  async update(data) {
    const csrf = await getCSRF();
    return this.execute("PUT", this.path, csrf, this.option, data);
  }

  async patch(data) {
    const csrf = await getCSRF();
    return this.execute("PATCH", this.path, csrf, this.option, data);
  }

  async delete() {
    const csrf = await getCSRF();
    return this.execute("DELETE", this.path, csrf, this.option);
  }

  async execute(method, path, csrf, option = {}, data = null) {
    const client = axios.create({
      baseURL: Space3DURL,
      headers: {
        "Content-Type": "application/json",
        Accept: "application/json",
        ENO_CSRF_TOKEN: csrf,
        SecurityContext: initApp.getCTX(), // 👈 added
        ...(option.headers || {}),
      },
      withCredentials: true,
    });

    try {
      const response = await client({
        method,
        url: path,
        data,
      });
      return response;
    } catch (err) {
      return err;
    }
  }

  csrf() {
    return getCSRF();
  }
}

async function getCSRF() {
  try {
    const api = new Api3DxService("/resources/v1/application/CSRF", {});

    const response = await api.execute(
      "GET",
      "/resources/v1/application/CSRF",
      null,
      {}
    );

    return response?.data?.csrf?.value;
  } catch (e) {
    throw new Error(e.message);
  }
}

export default Api3DxService;
