/* ---------- constants ---------- */
export const NODE_W = 220;
export const NODE_H = 85;

const H_SPACING = 350;
const V_SPACING = 150;

const MARGIN_X = 10;
const MARGIN_Y = 750;

/* ---------- GRAPH BUILDING ---------- */
export function buildGraph(raw) {
  const nodes = (raw.nodes || []).map((n) => ({
    id: String(n.id),
    type: n.type || "rectangle",
    title: n.title || n.label || n.id,
    subtitle: n.subtitle || "",
    startDate: n.startDate || "",
    dueDate: n.dueDate || "",
    assignees: n.assignees || [],
    status: n.status || "",
    maturity: n.maturity || "",
    // PATCH – PRESERVE YOUR CUSTOM FIELDS
    // ADD totalFloat here
    totalFloat: n.totalFloat || 0, // <-- ADD THIS LINE
    hierarchyDepth: n.hierarchyDepth ?? 0,
    isInitial: n.isInitial ?? false,
    hasChildren: n.hasChildren ?? false,
    width: NODE_W,
    height: NODE_H,
    x: 0,
    y: 0,
  }));

  const nodeById = Object.fromEntries(nodes.map((n) => [n.id, n]));

  const edges = (raw.edges || []).map((e) => ({
    from: String(e.from),
    to: String(e.to),
    type: e.type || "orthogonal",
    color: e.color || null,
    label: e.label || null,
    labelColor: e.labelColor || "#333",
  }));

  const adj = {};
  nodes.forEach((n) => (adj[n.id] = []));
  edges.forEach(
    (e) => nodeById[e.from] && nodeById[e.to] && adj[e.from].push(e.to)
  );

  return { nodes, nodeById, edges, adj };
}

/* ---------- TOPOLOGICAL SORT ---------- */
export function topologicalSort(nodes, adj) {
  const indeg = {};

  nodes.forEach((n) => (indeg[n.id] = 0));

  for (const u in adj) adj[u].forEach((v) => indeg[v]++);

  const q = [];
  nodes.forEach((n) => indeg[n.id] === 0 && q.push(n.id));

  const topo = [];

  while (q.length) {
    const u = q.shift();
    topo.push(u);

    (adj[u] || []).forEach((v) => {
      indeg[v]--;
      if (indeg[v] === 0) q.push(v);
    });
  }

  // Handle cycles.
  if (topo.length !== nodes.length) {
    nodes
      .map((n) => n.id)
      .filter((id) => !topo.includes(id))
      .forEach((id) => topo.push(id));
  }

  return topo;
}

/* ---------- COMPUTE LEVELS ---------- */
export function computeLevels(nodes, adj) {
  const topo = topologicalSort(nodes, adj);
  const level = {};

  nodes.forEach((n) => (level[n.id] = 0));

  for (const id of topo) {
    (adj[id] || []).forEach((v) => {
      if (level[v] < level[id] + 1) {
        level[v] = level[id] + 1;
      }
    });
  }

  return level;
}

/* ---------- ASSIGN POSITIONS ---------- */
export function assignPositions(nodes, levelMap) {
  const buckets = {};

  nodes.forEach((n) => {
    const lv = levelMap[n.id] ?? 0;
    (buckets[lv] ??= []).push(n);
    n.level = lv;
  });

  const maxCount = Math.max(
    ...Object.values(buckets).map((arr) => arr.length),
    1
  );

  Object.entries(buckets).forEach(([lvStr, arr]) => {
    const lv = Number(lvStr);

    const colSz = arr.length;
    const colH = (maxCount - 1) * V_SPACING;
    const thisH = (colSz - 1) * V_SPACING;

    const offsetY = MARGIN_Y + (colH - thisH) / 2;

    arr.forEach((node, i) => {
      node.x = MARGIN_X + lv * H_SPACING;
      node.y = offsetY + i * V_SPACING;
    });
  });
}

export function computeNodesBounds(nodes) {
  if (!nodes.length) return { minX: 0, minY: 0, maxX: 1200, maxY: 800 };

  let minX = Infinity,
    minY = Infinity,
    maxX = -Infinity,
    maxY = -Infinity;
  nodes.forEach((n) => {
    const nx = n.x || 0;
    const ny = n.y || 0;
    const w = n.width || 220;
    const h = n.height || 85;
    minX = Math.min(minX, nx);
    minY = Math.min(minY, ny);
    maxX = Math.max(maxX, nx + w);
    maxY = Math.max(maxY, ny + h);
  });
  const pad = 40;
  return {
    minX: minX,
    minY: minY - pad,
    maxX: maxX + pad,
    maxY: maxY + pad,
  };
}

export function getBoundsBasedPadding(bounds, viewBox) {
  const diagramW = bounds.maxX - bounds.minX;
  const diagramH = bounds.maxY - bounds.minY;

  // Guard against bad data
  if (diagramW <= 0 || diagramH <= 0) {
    return { left: 300, right: 500, top: 200, bottom: 200 };
  }

  // How much of the diagram is currently visible (0 → zoomed in, 1 → fully zoomed out)
  const visibleRatioX = Math.min(1, viewBox.w / diagramW);
  const visibleRatioY = Math.min(1, viewBox.h / diagramH);

  // Base padding driven by *current viewport size*
  const viewportPadX = viewBox.w * 0.35;
  const viewportPadY = viewBox.h * 0.35;

  // Blend diagram-awareness with viewport-awareness
  const basePadX = viewportPadX * (0.5 + visibleRatioX * 0.5);
  const basePadY = viewportPadY * (0.5 + visibleRatioY * 0.5);

  // Final directional padding with clamps
  return {
    left: Math.min(diagramW * 0.4, Math.max(200, basePadX)),

    right: Math.min(
      diagramW * 0.6, // allow more on right (layout bias)
      Math.max(400, basePadX * 1.2)
    ),

    top: Math.min(diagramH * 0.4, Math.max(150, basePadY)),

    bottom: Math.min(diagramH * 0.4, Math.max(150, basePadY)),
  };
}

export function getSafeBounds(nodes, edges, edgeControls) {
  let minX = Infinity;
  let minY = Infinity;
  let maxX = -Infinity;
  let maxY = -Infinity;

  nodes.forEach((n) => {
    minX = Math.min(minX, n.x);
    minY = Math.min(minY, n.y);
    maxX = Math.max(maxX, n.x + (n.width || 220));
    maxY = Math.max(maxY, n.y + (n.height || 85));
  });

  edges.forEach((e, i) => {
    const c = edgeControls?.[i];
    if (!c) return;

    if (c.cp1) {
      minX = Math.min(minX, c.cp1.x);
      minY = Math.min(minY, c.cp1.y);
      maxX = Math.max(maxX, c.cp1.x);
      maxY = Math.max(maxY, c.cp1.y);
    }
    if (c.cp2) {
      minX = Math.min(minX, c.cp2.x);
      minY = Math.min(minY, c.cp2.y);
      maxX = Math.max(maxX, c.cp2.x);
      maxY = Math.max(maxY, c.cp2.y);
    }
  });

  return { minX, minY, maxX, maxY };
}
