import Api3DxService from "../Enovia3DxApi.js";
// import initApp from "../../utility/initApp.js";
let URL = "/resources";
class enoviaService extends Api3DxService {
  constructor(path, option) {
    if (!option) option = {};
    super(path, option);
  }
  getCollabspaces() {
    this.path = `${URL}/modeler/pno/person?current=true&select=preferredcredentials&select=collabspaces`;
    return super.get();
  }
  getProjectData(projectId) {
    let taskLevel =
      window && window.widget ? window.widget.getValue("taskLevel") : 2;
     this.path = `${URL}/v1/modeler/projects/${projectId}?rollup=live&isCustomizedEnvironment=false&$include=all&$fields=all&level=${taskLevel}`;
    return super.get();
  }
}
export { enoviaService as default };