import React, {
  useEffect,
  useRef,
  useState,
  useCallback,
  useMemo,
  useReducer,
} from "react";
import RectangleNode from "./shapes/RectangleNode";
import EdgeRenderer from "./EdgeRenderer";
import Service from "../api/service";
import { animateViewBox } from "../utility/animateViewBox";
import { convertEnoviaToDiagram } from "../utility/convertEnoviaToDiagram";
import { exportDiagram } from "../utility/exportDiagram";
import { computeNodesBounds } from "../utility/flowHelpers";
import {
  buildGraph,
  computeLevels,
  assignPositions,
} from "../utility/flowHelpers";
import Minimap from "./MXMinimap";
import ScrollBars from "./ScrollBars";
import Loader from "./loader/Loader";
import ToastNotification, {
  showSuccessToast,
  showErrorToast,
  showInfoToast,
} from "./toasts/ToastNotification";
import {
  ZoomIn,
  ZoomOut,
  Refresh,
  Download,
  FitScreen,
} from "@mui/icons-material";
import TimelineIcon from "@mui/icons-material/Timeline"; // Fixed import
import html2canvas from "html2canvas";
import { computeHierarchyChain } from "../utility/hierarchyChainHelpers";

/* CONFIG */
const INITIAL_ZOOM_FACTOR = 0.85;
const MIN_VIEW_W = 700;
const MIN_VIEW_H = 550;
const VIEWPORT_PADDING = 250; // Buffer area for virtualization
const SCROLL_SENSITIVITY = 0.5; // <-- ADD THIS LINE
// Performance constants
const BATCH_UPDATE_DELAY = 16; // ~60fps
const VIRTUALIZATION_THRESHOLD = 50; // Number of nodes before virtualization kicks in

/* ========== STATE REDUCER ========== */
function diagramReducer(state, action) {
  switch (action.type) {
    case "SET_DIAGRAM_DATA":
      return {
        ...state,
        nodes: action.payload.nodes,
        edges: action.payload.edges,
        nodeMap: action.payload.nodeMap,
        edgeControls: action.payload.edgeControls,
        version: state.version + 1,
      };
    case "UPDATE_NODES":
      const newNodes = action.payload.nodes;
      const newNodeMap = Object.fromEntries(newNodes.map((n) => [n.id, n]));
      return {
        ...state,
        nodes: newNodes,
        nodeMap: newNodeMap,
        version: state.version + 1,
      };
    case "UPDATE_EDGE_CONTROL":
      return {
        ...state,
        edgeControls: {
          ...state.edgeControls,
          [action.payload.edgeIndex]: action.payload.control,
        },
      };
    case "INCREMENT_VERSION":
      return {
        ...state,
        version: state.version + 1,
      };
    default:
      return state;
  }
}

/* ========== DEBOUNCE UTILITY ========== */
function debounce(func, wait) {
  let timeout;
  return function executedFunction(...args) {
    const later = () => {
      clearTimeout(timeout);
      func(...args);
    };
    clearTimeout(timeout);
    timeout = setTimeout(later, wait);
  };
}

/* ========== MEMOIZED COMPONENTS ========== */
const MemoizedRectangleNode = React.memo(
  RectangleNode,
  (prevProps, nextProps) => {
    // Only re-render if these specific props change
    return (
      prevProps.x === nextProps.x &&
      prevProps.y === nextProps.y &&
      prevProps.width === nextProps.width &&
      prevProps.height === nextProps.height &&
      prevProps.isInChain === nextProps.isInChain &&
      prevProps.isHighlighted === nextProps.isHighlighted &&
      prevProps.opacity === nextProps.opacity &&
      prevProps.showCriticalPath === nextProps.showCriticalPath &&
      prevProps.status === nextProps.status &&
      prevProps.maturity === nextProps.maturity &&
      prevProps.hierarchyDepth === nextProps.hierarchyDepth &&
      prevProps.isExpanded === nextProps.isExpanded && // Add this line
      prevProps.hasChildren === nextProps.hasChildren && // Add this line
      prevProps.dragNode === nextProps.dragNode // Add this line
    );
  }
);

const MemoizedEdgeRenderer = React.memo(
  EdgeRenderer,
  (prevProps, nextProps) => {
    // Don't block updates for hover/interaction states
    if (
      prevProps.hoverEdgeIndex === nextProps.edgeIndex ||
      nextProps.hoverEdgeIndex === nextProps.edgeIndex ||
      prevProps.selectedIndex === nextProps.edgeIndex ||
      nextProps.selectedIndex === nextProps.edgeIndex
    ) {
      return false; // Always re-render if this edge is hovered/selected
    }

    const edgeChanged =
      !prevProps.edge || !nextProps.edge
        ? true
        : prevProps.edge.from !== nextProps.edge.from ||
          prevProps.edge.to !== nextProps.edge.to ||
          prevProps.edge.type !== nextProps.edge.type ||
          prevProps.edge.isCritical !== nextProps.edge.isCritical;

    const nodeChanged =
      prevProps.nodeById[prevProps.edge?.from]?.x !==
        nextProps.nodeById[nextProps.edge?.from]?.x ||
      prevProps.nodeById[prevProps.edge?.from]?.y !==
        nextProps.nodeById[nextProps.edge?.from]?.y ||
      prevProps.nodeById[prevProps.edge?.to]?.x !==
        nextProps.nodeById[nextProps.edge?.to]?.x ||
      prevProps.nodeById[prevProps.edge?.to]?.y !==
        nextProps.nodeById[nextProps.edge?.to]?.y;

    return (
      !edgeChanged &&
      !nodeChanged &&
      prevProps.isInChain === nextProps.isInChain &&
      prevProps.isHighlighted === nextProps.isHighlighted &&
      prevProps.opacity === nextProps.opacity &&
      prevProps.showCriticalPath === nextProps.showCriticalPath &&
      prevProps.chainActive === nextProps.chainActive
    );
  }
);

export default function FlowDiagram({ data }) {
  /* ========== REDUCER STATE ========== */
  const [diagramState, dispatch] = useReducer(diagramReducer, {
    nodes: [],
    edges: [],
    nodeMap: {},
    edgeControls: {},
    version: 0,
  });

  /* ========== LOCAL STATE ========== */
  const [fullData, setFullData] = useState({
    nodes: [],
    edges: [],
    nodeById: {},
  });
  const [expanded, setExpanded] = useState(new Set());
  const [activeDropdownNodeId, setActiveDropdownNodeId] = useState(null);

  const [expandDepth] = useState(999);
  const [preChainViewBox, setPreChainViewBox] = useState(null);
  const [preChainExpanded, setPreChainExpanded] = useState(new Set());

  const [selectedEdgeIndex, setSelectedEdgeIndex] = useState(null);
  const [hoverEdgeIndex, setHoverEdgeIndex] = useState(null);
  const [showCriticalOnly, setShowCriticalOnly] = useState(false);
  const [loading, setLoading] = useState(false);
  const [exportLoading, setExportLoading] = useState(false);
  const [activeInteraction, setActiveInteraction] = useState(null);

  /* ========== HIGHLIGHT CHAIN STATE ========== */
  const [highlightedChain, setHighlightedChain] = useState({
    nodeId: null,
    chainNodeIds: new Set(),
    chainEdgeIds: new Set(),
  });

  /* ========== VIEWBOX STATE ========== */
  const [viewBox, setViewBox] = useState({ x: 0, y: 0, w: 1200, h: 800 });

  /* ========== REFS ========== */
  const svgRef = useRef(null);
  const containerRef = useRef(null);
  const initialDone = useRef(false);

  const panningRef = useRef({
    active: false,
    startClient: { x: 0, y: 0 },
    startView: null,
  });

  const draggingRef = useRef({
    dragging: false,
    edgeIndex: null,
    offsetX: 0,
    offsetY: 0,
  });

  const nodeDragRef = useRef({
    active: false,
    nodeId: null,
    startClient: { x: 0, y: 0 },
    startNodePos: { x: 0, y: 0 },
  });

  /* ========== MEMOIZED VALUES ========== */
  const bounds = useMemo(() => {
    return computeNodesBounds(diagramState.nodes);
  }, [diagramState.nodes]);

  /* ========== VISIBLE ELEMENTS (VIRTUALIZATION) ========== */
  const { visibleNodes, visibleEdges } = useMemo(() => {
    const diagramWidth = bounds.maxX - bounds.minX;
    const diagramHeight = bounds.maxY - bounds.minY;
    const VIEWPORT_PADDING = Math.max(
      0.1 * Math.max(diagramWidth, diagramHeight),
      50
    );
    // If we have few nodes, don't bother with virtualization
    if (diagramState.nodes.length < VIRTUALIZATION_THRESHOLD) {
      return {
        visibleNodes: diagramState.nodes,
        visibleEdges: diagramState.edges,
      };
    }

    // Calculate viewport with padding for better UX
    const paddedViewBox = {
      x: viewBox.x - VIEWPORT_PADDING,
      y: viewBox.y - VIEWPORT_PADDING,
      w: viewBox.w + VIEWPORT_PADDING * 2,
      h: viewBox.h + VIEWPORT_PADDING * 2,
    };

    // Filter nodes in viewport
    const visibleNodeIds = new Set();
    const visibleNodes = diagramState.nodes.filter((node) => {
      const nodeRight = node.x + (node.width || 220);
      const nodeBottom = node.y + (node.height || 85);

      const isVisible = !(
        nodeRight < paddedViewBox.x ||
        node.x > paddedViewBox.x + paddedViewBox.w ||
        nodeBottom < paddedViewBox.y ||
        node.y > paddedViewBox.y + paddedViewBox.h
      );

      if (isVisible) visibleNodeIds.add(node.id);
      return isVisible;
    });

    // Filter edges connected to visible nodes or edges that cross viewport
    const visibleEdges = diagramState.edges.filter((edge) => {
      const fromNode = diagramState.nodeMap[edge.from];
      const toNode = diagramState.nodeMap[edge.to];

      if (!fromNode || !toNode) return false;

      // Edge is visible if either node is visible
      return visibleNodeIds.has(edge.from) || visibleNodeIds.has(edge.to);
    });

    return { visibleNodes, visibleEdges };
  }, [diagramState.nodes, diagramState.edges, diagramState.nodeMap, viewBox]);

  /* ========== DEBOUNCED FUNCTIONS ========== */
  const debouncedViewBoxChange = useMemo(
    () =>
      debounce((updater) => {
        setViewBox((prev) => {
          const newBox =
            typeof updater === "function" ? updater(prev) : updater;

          // Constrain within diagram bounds
          const maxAllowedX = bounds.maxX - newBox.w;
          const maxAllowedY = bounds.maxY - newBox.h;

          const constrainedX = Math.max(
            bounds.minX,
            Math.min(maxAllowedX, newBox.x)
          );
          const constrainedY = Math.max(
            bounds.minY,
            Math.min(maxAllowedY, newBox.y)
          );

          return {
            x: constrainedX,
            y: constrainedY,
            w: Math.max(
              MIN_VIEW_W,
              Math.min(bounds.maxX - bounds.minX, newBox.w)
            ),
            h: Math.max(
              MIN_VIEW_H,
              Math.min(bounds.maxY - bounds.minY, newBox.h)
            ),
          };
        });
      }, BATCH_UPDATE_DELAY),
    [bounds]
  );
  /* ========== VIEWBOX UPDATERS ========== */
  const viewBoxRef = useRef(viewBox);
  useEffect(() => {
    viewBoxRef.current = viewBox;
  }, [viewBox]);

  // Create a non-debounced immediate updater for animations
  const immediateViewBoxChange = useCallback((newViewBox) => {
    setViewBox((prev) => {
      const finalBox =
        typeof newViewBox === "function" ? newViewBox(prev) : newViewBox;
      return finalBox;
    });
  }, []);
  useEffect(() => {
  const handleGlobalClick = () => {
    setActiveDropdownNodeId(null);
  };

  document.addEventListener("mousedown", handleGlobalClick);

  return () => {
    document.removeEventListener("mousedown", handleGlobalClick);
  };
}, []);
  /* ========== CLIENT TO GRAPH COORDINATES ========== */
  const clientToGraph = useCallback(
    (clientX, clientY) => {
      const svg = svgRef.current;
      if (!svg) return { x: clientX, y: clientY };

      const rect = svg.getBoundingClientRect();
      const px = clientX - rect.left;
      const py = clientY - rect.top;

      const graphX = viewBox.x + (px / rect.width) * viewBox.w;
      const graphY = viewBox.y + (py / rect.height) * viewBox.h;

      return { x: graphX, y: graphY };
    },
    [viewBox]
  );

  /* ========== TOGGLE CRITICAL PATH ========== */
  const toggleCriticalPath = useCallback(() => {
    const newShowCriticalOnly = !showCriticalOnly;
    setShowCriticalOnly(newShowCriticalOnly);
    showInfoToast(
      newShowCriticalOnly ? "Critical Path Highlighted" : "Critical Path Hidden"
    );
  }, [showCriticalOnly]);

  /* ========== HIGHLIGHT CHAIN ========== */
  const highlightChain = useCallback(
    (nodeId, isClearingChain = false) => {
      // --- CASE 1: Exit chain view ---
      if (isClearingChain || highlightedChain.nodeId === nodeId) {
        const restoredExpanded = new Set(preChainExpanded);
        setExpanded(restoredExpanded);
        setHighlightedChain({
          nodeId: null,
          chainNodeIds: new Set(),
          chainEdgeIds: new Set(),
        });

        const subset = buildVisibleSubset(
          fullData,
          restoredExpanded,
          expandDepth
        );
        applyVisibleData(subset);

        if (preChainViewBox) {
          animateViewBox(viewBoxRef.current, preChainViewBox, 300, (frame) => {
            immediateViewBoxChange(frame);
          });
        }

        showInfoToast("Lineage chain lowered • Hierarchy restored");
        return;
      }

      // --- CASE 2: Enter chain view ---
      const currentViewBox = viewBoxRef.current;
      setPreChainExpanded(new Set(expanded));
      setPreChainViewBox(currentViewBox);

      const { chainNodeIds, chainEdgeIds } = computeHierarchyChain(
        nodeId,
        fullData.nodeById
      );

      const newExpanded = new Set(expanded);
      chainNodeIds.forEach((id) => {
        const n = fullData.nodeById[id];
        if (n?.hasChildren) newExpanded.add(id);
      });

      setExpanded(newExpanded);
      setHighlightedChain({ nodeId, chainNodeIds, chainEdgeIds });

      const subset = buildVisibleSubset(fullData, newExpanded, expandDepth);
      applyVisibleData(subset, nodeId); // Center on the node

      const node = fullData.nodeById[nodeId];
      const nodeTitle = node?.title || nodeId;

      const newlyExpandedCount = [...chainNodeIds].filter(
        (id) => !preChainExpanded.has(id) && fullData.nodeById[id]?.hasChildren
      ).length;

      showSuccessToast(
        `Elevated lineage chain for "${nodeTitle}" • ${newlyExpandedCount} nodes auto-expanded`
      );
    },
    [
      expanded,
      fullData,
      expandDepth,
      highlightedChain.nodeId,
      preChainExpanded,
      preChainViewBox,
    ]
  );

  /* ========== LOAD PROJECT ========== */
  const loadProject = useCallback(
    (projectId) => {
      setLoading(true);
      initialDone.current = false;

      setHighlightedChain({
        nodeId: null,
        chainNodeIds: new Set(),
        chainEdgeIds: new Set(),
      });
      setPreChainExpanded(new Set());
      setExpanded(new Set());
      setShowCriticalOnly(false);

      Service.EnoviaService()
        .getProjectData(projectId)
        .then((res) => {
          const converted = convertEnoviaToDiagram(res.data);
          setFullData(converted);
          const subset = buildVisibleSubset(converted, new Set(), expandDepth);
          applyVisibleData(subset);
          setLoading(false);
          setTimeout(
            () => showSuccessToast("Project Loaded Successfully!"),
            200
          );
        })
        .catch((err) => {
          console.error(err);
          setLoading(false);
          showErrorToast("Unable to fetch data.");
        });
    },
    [expandDepth]
  );

  /* ========== VISIBLE SUBSET BUILDER ========== */
  function buildVisibleSubset(converted, expandedSet, depthLimit) {
    const allNodes = converted.nodes || [];
    const allEdges = converted.edges || [];

    const childrenByParent = {};
    allNodes.forEach((n) => {
      const pid = n.parentId || null;
      (childrenByParent[pid] ??= []).push(n.id);
    });

    const visibleNodeIds = new Set();
    const initialIds = new Set();

    // Add root nodes
    (childrenByParent[null] || []).forEach((id) => {
      visibleNodeIds.add(id);
      initialIds.add(id);
    });

    // Expand based on depth
    for (let depth = 0; depth < depthLimit; depth++) {
      const currentIds = [...visibleNodeIds];
      currentIds.forEach((id) => {
        if (expandedSet.has(id)) {
          (childrenByParent[id] || []).forEach((childId) => {
            visibleNodeIds.add(childId);
          });
        }
      });
    }

    const visibleNodes = allNodes.filter((n) => visibleNodeIds.has(n.id));

    // Calculate hierarchy depth
    const idToDepth = {};
    function dfs(id, d) {
      idToDepth[id] = d;
      (childrenByParent[id] || []).forEach((childId) => {
        if (visibleNodeIds.has(childId)) dfs(childId, d + 1);
      });
    }
    (childrenByParent[null] || []).forEach((id) => {
      if (visibleNodeIds.has(id)) dfs(id, 0);
    });

    visibleNodes.forEach((n) => {
      n.hierarchyDepth = idToDepth[n.id] ?? 0;
      n.isInitial = initialIds.has(n.id);
    });

    const visibleEdges = allEdges.filter(
      (e) => visibleNodeIds.has(e.from) && visibleNodeIds.has(e.to)
    );

    return {
      nodes: visibleNodes,
      edges: visibleEdges,
      nodeById: Object.fromEntries(visibleNodes.map((n) => [n.id, n])),
    };
  }

  /* ========== APPLY VISIBLE DATA ========== */
  function applyVisibleData(subset, focusNodeId = null) {
    const g = buildGraph({ nodes: subset.nodes, edges: subset.edges });
    const levels = computeLevels(g.nodes, g.adj);
    assignPositions(g.nodes, levels);

    // Preserve flags
    g.nodes.forEach((node) => {
      node.isInitial = Boolean(subset.nodeById?.[node.id]?.isInitial);
    });

    // Get the new bounds from the positioned nodes BEFORE updating state
    const newBounds = computeNodesBounds(g.nodes);

    // Batch update all diagram data
    dispatch({
      type: "SET_DIAGRAM_DATA",
      payload: {
        nodes: g.nodes,
        edges: g.edges,
        nodeMap: Object.fromEntries(g.nodes.map((n) => [n.id, n])),
        edgeControls: Object.fromEntries(g.edges.map((_, i) => [i, undefined])),
      },
    });

    // Use requestAnimationFrame to ensure state is updated before centering
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        // Recenter camera if focusing on a node
        if (focusNodeId) {
          const node = g.nodes.find((n) => n.id === focusNodeId);
          if (node) {
            const currentBox = viewBoxRef.current;
            const target = {
              x: node.x + (node.width || 220) / 2 - currentBox.w / 2,
              y: node.y + (node.height || 85) / 2 - currentBox.h / 2,
              w: currentBox.w,
              h: currentBox.h,
            };

            // Constrain within the NEW bounds
            const maxAllowedX = newBounds.maxX - target.w;
            const maxAllowedY = newBounds.maxY - target.h;

            target.x = Math.max(
              newBounds.minX,
              Math.min(maxAllowedX, target.x)
            );
            target.y = Math.max(
              newBounds.minY,
              Math.min(maxAllowedY, target.y)
            );

            // Animate immediately
            animateViewBox(currentBox, target, 400, (frame) => {
              immediateViewBoxChange(frame);
            });
          }
          return;
        }
        const maxLevel = Math.max(...g.nodes.map((n) => n.level ?? 0));

        // Initial camera setup
        if (
          !initialDone.current &&
          g.nodes.length &&
          maxLevel <= 4 // 👈 only root or root + direct children
        ) {
          initialDone.current = true;

          const b = newBounds;
          const root = g.nodes[0];

          const rootCenterY = root.y + (root.height || 85) / 2;

          const MIN_VISIBLE_H = 300;
          const diagramH = b.maxY - b.minY;

          const h = Math.min(
            viewBoxRef.current.h,
            Math.max(diagramH + 150, MIN_VISIBLE_H)
          );

          const y = rootCenterY - h / 2;

          immediateViewBoxChange({
            x: viewBoxRef.current.x,
            y,
            w: viewBoxRef.current.w,
            h,
          });
        } else if (!initialDone.current && g.nodes.length) {
          initialDone.current = true;

          const root = g.nodes[0];

          // Vertical centering on root
          const rootCenterY = root.y + (root.height || 85) / 2;

          // Camera size (do NOT zoom out)
          const w = Math.min(viewBoxRef.current.w, MIN_VIEW_W);
          const h = Math.min(viewBoxRef.current.h, MIN_VIEW_H);

          // 👇 Camera placed RIGHT AFTER root
          const GAP_AFTER_ROOT = 130; // tweak: 20–80 feels good

          const newViewBox = {
            x: root.x + (root.width || 220) + GAP_AFTER_ROOT,
            y: rootCenterY - h / 2,
            w,
            h,
          };

          // Apply your EXISTING clamp
          const maxAllowedX = newBounds.maxX - newViewBox.w;
          const maxAllowedY = newBounds.maxY - newViewBox.h;

          newViewBox.x = Math.max(
            newBounds.minX,
            Math.min(maxAllowedX, newViewBox.x)
          );
          newViewBox.y = Math.max(
            newBounds.minY,
            Math.min(maxAllowedY, newViewBox.y)
          );

          immediateViewBoxChange(newViewBox);
        }
      });
    });
  }

  /* ========== NODE DOUBLE CLICK ========== */
  const onNodeDoubleClick = useCallback(
    (nodeId) => {
      // Store current expanded state before modifying
      const currentExpanded = new Set(expanded);
      const next = new Set(expanded);

      if (next.has(nodeId)) {
        // Collapse
        next.delete(nodeId);
        // Remove all descendants
        const childMap = {};
        fullData.nodes.forEach((n) => {
          childMap[n.parentId] ??= [];
          childMap[n.parentId].push(n.id);
        });
        const stack = [nodeId];
        while (stack.length) {
          const cur = stack.pop();
          (childMap[cur] || []).forEach((k) => {
            next.delete(k);
            stack.push(k);
          });
        }
      } else {
        // Expand
        next.add(nodeId);
      }

      // Update state
      setExpanded(next);

      // Build subset with NEW expanded state
      const subset = buildVisibleSubset(fullData, next, expandDepth);
      applyVisibleData(subset, nodeId);
    },
    [expanded, fullData, expandDepth]
  );

  /* ========== PAN HANDLERS ========== */
  const onMouseDownSvg = useCallback(
    (e) => {
      if (e.button !== 0 || activeInteraction) return;

      setActiveInteraction("panning");
      panningRef.current = {
        active: true,
        startClient: { x: e.clientX, y: e.clientY },
        startView: { ...viewBox },
      };

      const moveHandler = (moveEvent) => {
        if (!panningRef.current.active) return;
        const svg = svgRef.current;
        if (!svg) return;

        const rect = svg.getBoundingClientRect();
        const dxPixels = moveEvent.clientX - panningRef.current.startClient.x;
        const dyPixels = moveEvent.clientY - panningRef.current.startClient.y;

        const dxGraph =
          -dxPixels * (panningRef.current.startView.w / rect.width);
        const dyGraph =
          -dyPixels * (panningRef.current.startView.h / rect.height);

        debouncedViewBoxChange({
          ...viewBox,
          x: panningRef.current.startView.x + dxGraph,
          y: panningRef.current.startView.y + dyGraph,
        });
      };

      const upHandler = () => {
        panningRef.current.active = false;
        setActiveInteraction(null);
        document.removeEventListener("mousemove", moveHandler);
        document.removeEventListener("mouseup", upHandler);
      };

      document.addEventListener("mousemove", moveHandler);
      document.addEventListener("mouseup", upHandler);
      e.preventDefault();
    },
    [activeInteraction, viewBox, debouncedViewBoxChange]
  );

  /* ========== WHEEL HANDLING ========== */
  /* ========== WHEEL HANDLING ========== */
  const handleWheel = useCallback(
    (e) => {
      e.preventDefault();

      const svgRect = svgRef.current?.getBoundingClientRect();
      if (!svgRect) return;

      // Capture event values immediately
      const deltaX = e.deltaX;
      const deltaY = e.deltaY;
      const isCtrlPressed = e.ctrlKey || e.metaKey;
      const isShiftPressed = e.shiftKey;

      const scrollFrame = () => {
        if (isCtrlPressed) {
          // ZOOM
          const zoomFactor = 1.1;
          const mouseX = e.clientX - svgRect.left;
          const mouseY = e.clientY - svgRect.top;

          setViewBox((prev) => {
            const graphX = prev.x + (mouseX / svgRect.width) * prev.w;
            const graphY = prev.y + (mouseY / svgRect.height) * prev.h;

            const newW = deltaY > 0 ? prev.w * zoomFactor : prev.w / zoomFactor;
            const newH = deltaY > 0 ? prev.h * zoomFactor : prev.h / zoomFactor;

            const newX = graphX - (mouseX / svgRect.width) * newW;
            const newY = graphY - (mouseY / svgRect.height) * newH;

            // Constrain zoom
            const maxAllowedX = bounds.maxX - newW;
            const maxAllowedY = bounds.maxY - newH;

            return {
              x: Math.max(bounds.minX, Math.min(maxAllowedX, newX)),
              y: Math.max(bounds.minY, Math.min(maxAllowedY, newY)),
              w: Math.max(
                MIN_VIEW_W,
                Math.min(bounds.maxX - bounds.minX, newW)
              ),
              h: Math.max(
                MIN_VIEW_H,
                Math.min(bounds.maxY - bounds.minY, newH)
              ),
            };
          });
        } else {
          // SCROLL - immediate response
          const scrollSpeed = 0.5;

          setViewBox((prev) => {
            // For horizontal scrolling: shift+wheel OR wheel with deltaX
            const effectiveDeltaX = isShiftPressed ? deltaY : deltaX;
            const effectiveDeltaY = isShiftPressed ? 0 : deltaY;

            const newX =
              prev.x + effectiveDeltaX * scrollSpeed * (prev.w / svgRect.width);
            const newY =
              prev.y +
              effectiveDeltaY * scrollSpeed * (prev.h / svgRect.height);

            // Constrain immediately
            const maxAllowedX = bounds.maxX - prev.w;
            const maxAllowedY = bounds.maxY - prev.h;

            return {
              ...prev,
              x: Math.max(bounds.minX, Math.min(maxAllowedX, newX)),
              y: Math.max(bounds.minY, Math.min(maxAllowedY, newY)),
            };
          });
        }
      };

      // Use requestAnimationFrame for smooth 60fps scrolling
      requestAnimationFrame(scrollFrame);
    },
    [bounds]
  );

  /* ========== NODE DRAGGING ========== */
  const startNodeDrag = useCallback(
    (nodeId, clientX, clientY) => {
      const node = diagramState.nodeMap[nodeId];
      if (!node) return;

      nodeDragRef.current = {
        active: true,
        nodeId,
        startClient: { x: clientX, y: clientY },
        startNodePos: { x: node.x, y: node.y },
      };

      setActiveInteraction("node");
      document.body.style.userSelect = "none";
    },
    [diagramState.nodeMap]
  );

  useEffect(() => {
    const handleMouseMove = (e) => {
      if (!nodeDragRef.current.active) return;

      const { nodeId, startClient, startNodePos } = nodeDragRef.current;
      const dxPixels = e.clientX - startClient.x;
      const dyPixels = e.clientY - startClient.y;

      const svg = svgRef.current;
      if (!svg) return;

      const rect = svg.getBoundingClientRect();
      const dxGraph = dxPixels * (viewBox.w / rect.width);
      const dyGraph = dyPixels * (viewBox.h / rect.height);

      const newX = startNodePos.x + dxGraph;
      const newY = startNodePos.y + dyGraph;

      // Update single node position
      dispatch({
        type: "UPDATE_NODES",
        payload: {
          nodes: diagramState.nodes.map((n) =>
            n.id === nodeId ? { ...n, x: newX, y: newY } : n
          ),
        },
      });
    };

    const handleMouseUp = () => {
      nodeDragRef.current.active = false;
      setActiveInteraction(null);
      document.body.style.userSelect = "";
    };

    document.addEventListener("mousemove", handleMouseMove);
    document.addEventListener("mouseup", handleMouseUp);

    return () => {
      document.removeEventListener("mousemove", handleMouseMove);
      document.removeEventListener("mouseup", handleMouseUp);
    };
  }, [diagramState.nodes, viewBox]);

  /* ========== EDGE DRAGGING ========== */
  const onStartEdgeDrag = useCallback(
    (edgeIndex, { clientX, clientY }) => {
      setActiveInteraction("edge");
      const gPos = clientToGraph(clientX, clientY);
      draggingRef.current = {
        dragging: true,
        edgeIndex,
        offsetX: gPos.x,
        offsetY: gPos.y,
      };
      document.body.style.userSelect = "none";
    },
    [clientToGraph]
  );

  useEffect(() => {
    const move = (e) => {
      if (!draggingRef.current.dragging) return;
      const idx = draggingRef.current.edgeIndex;
      const prev = draggingRef.current;
      const gPos = clientToGraph(e.clientX, e.clientY);
      const dx = gPos.x - prev.offsetX;
      const dy = gPos.y - prev.offsetY;

      draggingRef.current.offsetX = gPos.x;
      draggingRef.current.offsetY = gPos.y;

      dispatch({
        type: "UPDATE_EDGE_CONTROL",
        payload: {
          edgeIndex: idx,
          control: {
            ...diagramState.edgeControls[idx],
            cp1: diagramState.edgeControls[idx]?.cp1
              ? {
                  x: diagramState.edgeControls[idx].cp1.x + dx,
                  y: diagramState.edgeControls[idx].cp1.y + dy,
                }
              : null,
            cp2: diagramState.edgeControls[idx]?.cp2
              ? {
                  x: diagramState.edgeControls[idx].cp2.x + dx,
                  y: diagramState.edgeControls[idx].cp2.y + dy,
                }
              : null,
          },
        },
      });
    };

    const up = () => {
      draggingRef.current = {
        dragging: false,
        edgeIndex: null,
        offsetX: 0,
        offsetY: 0,
      };
      setActiveInteraction(null);
      document.body.style.userSelect = "";
    };

    window.addEventListener("mousemove", move);
    window.addEventListener("mouseup", up);

    return () => {
      window.removeEventListener("mousemove", move);
      window.removeEventListener("mouseup", up);
    };
  }, [diagramState.edgeControls, clientToGraph]);

  /* ========== FIT TO SCREEN ========== */
  const fitToScreen = useCallback(() => {
    const b = bounds;
    const padding = 0;
    const paddedWidth = Math.max(100, b.maxX - b.minX + padding * 2);
    const paddedHeight = Math.max(100, b.maxY - b.minY + padding * 2);

    debouncedViewBoxChange({
      x: b.minX - padding,
      y: b.minY - padding,
      w: paddedWidth,
      h: paddedHeight,
    });
  }, [bounds, debouncedViewBoxChange]);

  const handleExportDiagram = async () => {
    const svg = svgRef.current;
    const nodes = diagramState.nodes; // <- Add this line
    if (!svg) {
      showErrorToast("No diagram found to export");
      return;
    }

    setExportLoading(true);

    try {
      const projectName = data?.displayName || data?.objectId || "unknown";
      const b = computeNodesBounds(nodes);
      const diagramWidth = Math.max(1, b.maxX - b.minX);
      const diagramHeight = Math.max(1, b.maxY - b.minY);

      const LARGE_DIAGRAM_AREA = 2000 * 2000;
      const area = diagramWidth * diagramHeight;

      if (area > LARGE_DIAGRAM_AREA) {
        await exportDiagram(
          svg,
          nodes,
          data?.objectId || "unknown",
          computeNodesBounds,
          viewBox,
          projectName
        );
      } else {
        await exportAsPNG(); // Will use diagramState.nodes internally
      }
    } catch (err) {
      console.error("handleExportDiagram failed:", err);
      showErrorToast("Export failed: " + (err?.message || "Unknown"));
    } finally {
      setExportLoading(false);
    }
  };
  /* ========== EXPORT (using html2canvas) ========== */
  const exportAsPNG = async () => {
    const svg = svgRef.current;
    const nodes = diagramState.nodes; // <- Make sure nodes is defined
    if (!svg) {
      showErrorToast("No diagram found to export");
      return;
    }

    setExportLoading(true);

    setTimeout(async () => {
      try {
        // toast.info("Exporting diagram...", { autoClose: 2000 });

        // Get project ID from data prop
        const projectId = data?.objectId || "unknown";

        // Create filename: PertDiagram_projectID.png
        const projectName = data?.displayName || data?.objectId || "unknown";
        const fileName = `PertDiagram_${projectName}.png`;

        // Get diagram bounds
        const b = computeNodesBounds(nodes);
        if (
          !b ||
          b.maxX === undefined ||
          b.minX === undefined ||
          b.maxY === undefined ||
          b.minY === undefined
        ) {
          showErrorToast("Cannot determine diagram bounds");
          return;
        }

        const padding = 20;
        const diagramWidth = Math.max(200, b.maxX - b.minX);
        const diagramHeight = Math.max(200, b.maxY - b.minY);

        if (diagramWidth > 10000 || diagramHeight > 10000) {
          showErrorToast("Diagram is too large to export");
          return;
        }
        // Create a temporary container for the SVG
        const tempDiv = document.createElement("div");
        tempDiv.style.position = "absolute";
        tempDiv.style.left = "-9999px";
        tempDiv.style.top = "-9999px";
        tempDiv.style.width = `${diagramWidth + padding * 2}px`;
        tempDiv.style.height = `${diagramHeight + padding * 2}px`;
        tempDiv.style.backgroundColor = "white";
        document.body.appendChild(tempDiv);

        // Clone the SVG
        const clonedSvg = svg.cloneNode(true);

        // Set up the cloned SVG for export
        const exportWidth = diagramWidth + padding * 2;
        const exportHeight = diagramHeight + padding * 2;

        clonedSvg.setAttribute("width", exportWidth);
        clonedSvg.setAttribute("height", exportHeight);
        clonedSvg.setAttribute(
          "viewBox",
          `${b.minX - padding} ${b.minY - padding} ${
            b.maxX - b.minX + padding * 2
          } ${b.maxY - b.minY + padding * 2}`
        );
        clonedSvg.style.backgroundColor = "white";

        // Add white background rectangle
        const bgRect = document.createElementNS(
          "http://www.w3.org/2000/svg",
          "rect"
        );
        bgRect.setAttribute("x", b.minX - padding);
        bgRect.setAttribute("y", b.minY - padding);
        bgRect.setAttribute("width", exportWidth);
        bgRect.setAttribute("height", exportHeight);
        bgRect.setAttribute("fill", "white");
        clonedSvg.insertBefore(bgRect, clonedSvg.firstChild);

        tempDiv.appendChild(clonedSvg);

        // Use html2canvas for reliable export
        const canvas = await html2canvas(tempDiv, {
          backgroundColor: "white",
          scale: 2, // Higher resolution
          useCORS: true,
          logging: false,
          width: exportWidth,
          height: exportHeight,
        });

        // Convert to PNG and trigger download
        const pngDataUrl = canvas.toDataURL("image/png");
        const link = document.createElement("a");
        // use your FlowDiagram `data` prop
        link.download = `PertDiagram_${projectName}.png`; // use projectName
        link.href = pngDataUrl;
        link.click();

        // Clean up
        document.body.removeChild(tempDiv);
        showSuccessToast("Diagram exported successfully!");
      } catch (err) {
        console.error("Export error:", err);
        showErrorToast("Export failed: " + (err.message || "Unknown error"));

        // Clean up temp div if it exists
        const tempDiv = document.querySelector('[style*="left: -9999px"]');
        if (tempDiv && tempDiv.parentNode === document.body) {
          document.body.removeChild(tempDiv);
        }
      } finally {
        setExportLoading(false);
      }
    }, 10);
  };
  /* ========== EFFECTS ========== */
  useEffect(() => {
    if (data?.objectId) {
      loadProject(data.objectId);
    }
  }, [data, loadProject]);

  /* ========== EVENT DELEGATION HANDLER ========== */
  const handleSvgClick = useCallback(
    (e) => {
      // Find clicked element
      let target = e.target;
      while (target && target !== svgRef.current) {
        if (target.dataset?.nodeId) {
          // Node clicked
          if (e.detail === 2) {
            // Double click
            onNodeDoubleClick(target.dataset.nodeId);
          }
          return;
        }
        if (target.dataset?.edgeIndex) {
          // Edge clicked
          setSelectedEdgeIndex(parseInt(target.dataset.edgeIndex));
          return;
        }
        target = target.parentNode;
      }

      // Clicked on empty space
      setSelectedEdgeIndex(null);
    },
    [onNodeDoubleClick]
  );

  /* ========== RENDER ========== */
  return (
    <div
      style={{
        width: "100%",
        height: "100vh",
        position: "relative",
        background: "white",
        overflow: "hidden",
      }}
    >
      {loading && (
        <Loader
          message="Fetching Project Data..."
          size="medium"
          overlay={true}
        />
      )}
      {exportLoading && (
        <Loader
          message="Exporting diagram..."
          size="small"
          overlay={true}
          blur={false}
        />
      )}
      <ToastNotification />
      {/* Toolbar */}
      <div
        style={{
          position: "absolute",
          top: 12,
          right: 14,
          zIndex: 2000,
          display: "flex",
          gap: 6,
          background: "rgba(255, 255, 255, 0.9)",
          backdropFilter: "blur(10px)",
          borderRadius: "10px",
          padding: "2px",
          boxShadow: "0 4px 12px rgba(0, 0, 0, 0.1)",
          border: "1px solid rgba(0, 0, 0, 0.08)",
        }}
      >
        <button
          className="toolbar-btn"
          title="Reload"
          onClick={(e) => {
            e.stopPropagation();
            loadProject(data?.objectId);
          }}
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            width: "25px",
            height: "25px",
            borderRadius: "6px",
            border: "none",
            background: "transparent",
            cursor: "pointer",
            color: "#5f6368",
            transition: "all 0.2s ease",
            borderRight: "1px solid rgba(0, 0, 0, 0.1)",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "rgba(66, 133, 244, 0.1)";
            e.currentTarget.style.color = "#4285f4";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "transparent";
            e.currentTarget.style.color = "#5f6368";
          }}
        >
          <Refresh sx={{ fontSize: 16 }} />
        </button>

        <button
          className="toolbar-btn"
          title="Zoom In"
          onClick={() =>
            debouncedViewBoxChange((v) => ({
              ...v,
              w: v.w * 0.9,
              h: v.h * 0.9,
            }))
          }
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            width: "25px",
            height: "25px",
            borderRadius: "6px",
            border: "none",
            background: "transparent",
            cursor: "pointer",
            color: "#5f6368",
            transition: "all 0.2s ease",
            borderRight: "1px solid rgba(0, 0, 0, 0.1)",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "rgba(66, 133, 244, 0.1)";
            e.currentTarget.style.color = "#4285f4";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "transparent";
            e.currentTarget.style.color = "#5f6368";
          }}
        >
          <ZoomIn sx={{ fontSize: 16 }} />
        </button>

        <button
          className="toolbar-btn"
          title="Zoom Out"
          onClick={() =>
            debouncedViewBoxChange((v) => ({
              ...v,
              w: v.w * 1.1,
              h: v.h * 1.1,
            }))
          }
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            width: "25px",
            height: "25px",
            borderRadius: "6px",
            border: "none",
            background: "transparent",
            cursor: "pointer",
            color: "#5f6368",
            transition: "all 0.2s ease",
            borderRight: "1px solid rgba(0, 0, 0, 0.1)",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "rgba(66, 133, 244, 0.1)";
            e.currentTarget.style.color = "#4285f4";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "transparent";
            e.currentTarget.style.color = "#5f6368";
          }}
        >
          <ZoomOut sx={{ fontSize: 16 }} />
        </button>

        <button
          className="toolbar-btn"
          title="Fit to Screen"
          onClick={fitToScreen}
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            width: "25px",
            height: "25px",
            borderRadius: "6px",
            border: "none",
            background: "transparent",
            cursor: "pointer",
            color: "#5f6368",
            transition: "all 0.2s ease",
            borderRight: "1px solid rgba(0, 0, 0, 0.1)",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "rgba(66, 133, 244, 0.1)";
            e.currentTarget.style.color = "#4285f4";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "transparent";
            e.currentTarget.style.color = "#5f6368";
          }}
        >
          <FitScreen sx={{ fontSize: 16 }} />
        </button>

        <button
          className="toolbar-btn"
          title={
            showCriticalOnly ? "Hide Critical Path" : "Highlight Critical Path"
          }
          onClick={(e) => {
            e.stopPropagation();
            toggleCriticalPath();
          }}
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            width: "25px",
            height: "25px",
            borderRadius: "6px",
            border: "none",
            background: showCriticalOnly
              ? "rgba(220, 38, 38, 0.15)"
              : "transparent",
            cursor: "pointer",
            color: showCriticalOnly ? "#dc2626" : "#5f6368",
            transition: "all 0.2s ease",
            borderRight: "1px solid rgba(0, 0, 0, 0.1)",
          }}
          onMouseEnter={(e) => {
            if (!showCriticalOnly) {
              e.currentTarget.style.background = "rgba(66, 133, 244, 0.1)";
              e.currentTarget.style.color = "#4285f4";
            }
          }}
          onMouseLeave={(e) => {
            if (!showCriticalOnly) {
              e.currentTarget.style.background = "transparent";
              e.currentTarget.style.color = "#5f6368";
            }
          }}
        >
          <TimelineIcon
            sx={{
              fontSize: 16,
              color: showCriticalOnly ? "#dc2626" : "inherit",
            }}
          />
        </button>

        <button
          className="toolbar-btn"
          title="Export Diagram"
          onClick={handleExportDiagram}
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            width: "25px",
            height: "25px",
            borderRadius: "6px",
            border: "none",
            background: "transparent",
            cursor: "pointer",
            color: "#5f6368",
            transition: "all 0.2s ease",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "rgba(66, 133, 244, 0.1)";
            e.currentTarget.style.color = "#4285f4";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "transparent";
            e.currentTarget.style.color = "#5f6368";
          }}
        >
          <Download sx={{ fontSize: 16 }} />
        </button>
      </div>
      {/* Main container */}
      <div
        ref={containerRef}
        style={{
          width: "100%",
          height: "100%",
          position: "relative",
          overflow: "hidden",
        }}
        onWheel={handleWheel}
      >
        <ScrollBars
          viewBox={viewBox}
          diagramBounds={bounds}
          onViewBoxChange={debouncedViewBoxChange}
          setActiveInteraction={setActiveInteraction}
        />

        <Minimap
          nodes={diagramState.nodes}
          edges={diagramState.edges}
          diagramBounds={bounds}
          viewBox={viewBox}
          onViewBoxChange={debouncedViewBoxChange}
          setActiveInteraction={setActiveInteraction}
          showCriticalPath={showCriticalOnly}
          highlightedChain={highlightedChain}
        />

        {/* Single SVG layer with optimized rendering */}
        <svg
          ref={svgRef}
          width="100%"
          height="100%"
          viewBox={`${viewBox.x} ${viewBox.y} ${viewBox.w} ${viewBox.h}`}
          style={{
            display: "block",
            touchAction: "none",
            userSelect: "none",
            width: "100%",
            height: "100%",
            cursor: activeInteraction === "panning" ? "grabbing" : "grab",
          }}
          onMouseDown={onMouseDownSvg}
          onClick={handleSvgClick}
        >
          <defs>
            <marker
              id="arrow-flow-normal"
              markerWidth="10"
              markerHeight="10"
              refX="8"
              refY="5"
              orient="auto"
              markerUnits="userSpaceOnUse"
            >
              <path d="M0,0 L0,10 L10,5 z" fill="#333" />
            </marker>

            <marker
              id="arrow-flow-critical"
              markerWidth="10"
              markerHeight="10"
              refX="8"
              refY="5"
              orient="auto"
              markerUnits="userSpaceOnUse"
            >
              <path d="M0,0 L0,10 L10,5 z" fill="#CC0000" />
            </marker>
            <filter
              id="chainNodeElevation"
              x="-40%"
              y="-40%"
              width="180%"
              height="180%"
            >
              <feDropShadow
                dx="0"
                dy="4"
                stdDeviation="8"
                floodColor="rgb(0,0,0)"
                floodOpacity="0.3"
              />
              <feDropShadow
                dx="0"
                dy="8"
                stdDeviation="12"
                floodColor="rgb(0,0,0)"
                floodOpacity="0.2"
              />
            </filter>

            <filter
              id="criticalNodeGlow"
              x="-40%"
              y="-40%"
              width="180%"
              height="180%"
            >
              <feDropShadow
                dx="0"
                dy="0"
                stdDeviation="6"
                floodColor="rgb(204,0,0)"
                floodOpacity="1"
              />
            </filter>

            <filter id="nodeHover" x="-30%" y="-30%" width="160%" height="160%">
              <feDropShadow
                dx="0"
                dy="0"
                stdDeviation="4"
                floodColor="rgb(66,133,244)"
                floodOpacity="0.6"
              />
            </filter>

            <filter
              id="chainAndCriticalNode"
              x="-40%"
              y="-40%"
              width="180%"
              height="180%"
            >
              <feDropShadow
                dx="0"
                dy="4"
                stdDeviation="8"
                floodColor="rgb(0,0,0)"
                floodOpacity="0.3"
              />
              <feDropShadow
                dx="0"
                dy="8"
                stdDeviation="12"
                floodColor="rgb(0,0,0)"
                floodOpacity="0.2"
              />
              <feDropShadow
                dx="0"
                dy="0"
                stdDeviation="6"
                floodColor="rgb(204,0,0)"
                floodOpacity="1"
              />
            </filter>
          </defs>

          <g>
            {/* Render visible edges with chain highlighting */}
            {visibleEdges.map((edge, i) => {
              const edgeKey = `${edge.from}=>${edge.to}#${edge.type}`;
              const isChainEdge = highlightedChain.chainEdgeIds.has(edgeKey);
              const isInChain = highlightedChain.nodeId && isChainEdge;
              const edgeOpacity = highlightedChain.nodeId
                ? isInChain
                  ? 1
                  : 0.15
                : showCriticalOnly && !edge.isCritical
                ? 0.4
                : 1;
              return (
                <MemoizedEdgeRenderer
                  key={`edge-${i}-${diagramState.version}`}
                  edge={edge}
                  edgeIndex={i}
                  nodeById={diagramState.nodeMap}
                  selectedIndex={selectedEdgeIndex}
                  onSelectEdge={setSelectedEdgeIndex}
                  edgeControls={diagramState.edgeControls}
                  onStartEdgeDrag={
                    highlightedChain.nodeId ? undefined : onStartEdgeDrag
                  }
                  hoverEdgeIndex={hoverEdgeIndex}
                  setHoverEdgeIndex={setHoverEdgeIndex}
                  showCriticalPath={showCriticalOnly}
                  isInChain={isInChain}
                  chainActive={Boolean(highlightedChain.nodeId)}
                  opacity={edgeOpacity}
                  data-edge-index={i}
                  onHoverEnter={
                    highlightedChain.nodeId && !isInChain
                      ? undefined
                      : () => setHoverEdgeIndex(i)
                  }
                  onHoverLeave={
                    highlightedChain.nodeId && !isInChain
                      ? undefined
                      : () => setHoverEdgeIndex(null)
                  }
                />
              );
            })}

            {/* Render visible nodes with chain highlighting */}
            {visibleNodes.map((node) => {
              const isChainNode = highlightedChain.chainNodeIds.has(node.id);
              const isInChain = highlightedChain.nodeId && isChainNode;
              const isCritical = showCriticalOnly && node.totalFloat === 0;

              const nodeOpacity = highlightedChain.nodeId
                ? isInChain
                  ? 1
                  : 0.3
                : showCriticalOnly
                ? isCritical
                  ? 1
                  : 0.3
                : 1;

              console.log(`Node ${node.id}:`, {
                highlightedChainNodeId: highlightedChain.nodeId,
                isChainNode,
                isInChain,
              });
              return (
                <MemoizedRectangleNode
                  key={`node-${node.id}-${diagramState.version}`}
                  {...node}
                  onMouseDown={(e) => {
                    if (highlightedChain.nodeId && !isInChain) return;
                    e.stopPropagation();
                    startNodeDrag(node.id, e.clientX, e.clientY);
                  }}
                  onDoubleClick={() => {
                    if (highlightedChain.nodeId && !isInChain) return;
                    onNodeDoubleClick(node.id);
                  }}
                  dragNode={
                    nodeDragRef.current.active
                      ? nodeDragRef.current.nodeId
                      : null
                  }
                  showCriticalPath={showCriticalOnly}
                   activeDropdownNodeId={activeDropdownNodeId}
  setActiveDropdownNodeId={setActiveDropdownNodeId}
                  loading={loading}
                  onHighlightChain={highlightChain}
                  isInChain={isInChain}
                  isHighlighted={isChainNode}
                  opacity={nodeOpacity}
                  data-node-id={node.id}
                  filter={isInChain ? "url(#chainNodeElevation)" : undefined}
                  // Make sure these props are passed
                  isExpanded={expanded.has(node.id)} // Add this
                  hasChildren={node.hasChildren} // Add this
                />
              );
            })}
          </g>
        </svg>
      </div>
    </div>
  );
}
