import React, { useEffect, useState } from "react";
import DragDropProject from "./components/DragDropProject";

/* global requirejs */

function App({ widget }) {
  const [authorized, setAuthorized] = useState(null);

  async function getUserDetails() {
    try {
      if (typeof requirejs !== "undefined") {
        return requirejs("DS/PlatformAPI/PlatformAPI").getUser();
      } else {
        return { login: "localUser" }; // fallback for local
      }
    } catch (e) {
      return { login: "localUser" };
    }
  }

  useEffect(() => {
    async function checkAccess() {
      try {
        const userDetails = await getUserDetails();
        const currentUser = userDetails.login;
        const currentDomain = window.location.hostname;

        console.log("User:", currentUser);
        console.log("Domain:", currentDomain);

        const response = await fetch(
          `https://bwcmaheshp.github.io/Pert_Chart_Build/license.json?cb=${Date.now()}_${Math.random()}`,
          { cache: "no-store" },
        );

        const licenseData = await response.json();

        // 🔹 Match user + domain
        const userEntry = licenseData.find(
          (user) => user.login === currentUser && user.domain === currentDomain,
        );

        if (!userEntry) {
          console.log("User not authorized for this domain");
          setAuthorized(false);
          return;
        }

        // 🔹 Expiry check
        const isNotExpired = new Date() <= new Date(userEntry.expiry);

        if (isNotExpired) {
          setAuthorized(true);
        } else {
          console.log("License expired");
          setAuthorized(false);
        }
      } catch (error) {
        console.error("Error:", error);
        setAuthorized(false);
      }
    }

    checkAccess();
  }, []);

  if (authorized === null) return <div>Loading...</div>;

  if (!authorized)
    return (
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          height: "100vh",
          fontFamily: "sans-serif",
          color: "#721c24",
          background: "#f8d7da",
          border: "1px solid #f5c6cb",
          borderRadius: "8px",
          padding: "32px",
          textAlign: "center",
        }}
      >
        <h2 style={{ margin: "0 0 8px" }}>⛔ Access Denied</h2>
        <p style={{ margin: 0, fontSize: "14px" }}>
          You are not authorized to access this content.
        </p>
      </div>
    );

  return (
    <div style={{ textAlign: "center", justifyContent: "left" }}>
      <DragDropProject widget={widget} />
    </div>
  );
}

export default App;
