export function convertEnoviaToDiagram(enoviaJson) {
  if (!enoviaJson || !enoviaJson.data || !enoviaJson.data.length)
    return { nodes: [], edges: [], nodeById: {} }; // modify: include nodeById

  const proj = enoviaJson.data[0];
  const tasks = proj.relateddata?.tasks || [];

  const nodes = [];
  const nodeById = {};
  const edges = [];

  const formateDate = (d) => {
    if (!d) return "";
    const date = new Date(d);

    return date.toLocaleDateString("en-US", {
      month: "short",
      day: "2-digit",
      year: "numeric",
    });
  };

  // modify: extractor to safely get children from multiple possible locations
  const getChildrenArray = (task) => {
    if (Array.isArray(task.children)) return task.children;
    if (Array.isArray(task.relateddata?.children))
      return task.relateddata.children;
    if (Array.isArray(task.relateddata?.tasks)) return task.relateddata.tasks;
    if (Array.isArray(task.relateddata?.subTasks))
      return task.relateddata.subTasks;
    return [];
  };

  // modify: safe ID getter (prevents missing id issues)
  const getId = (t) =>
    t?.id ||
    t?.identifier ||
    (t?.dataelements && t.dataelements.objectId) ||
    null;

  const walk = (task, parentId = null) => {
    const t = task || {};
    const id = getId(t) || Math.random().toString(36).slice(2, 9); // modify: safer ID

    // Extract totalFloat - ADD THIS
    let totalFloat = 0;
    if (t.dataelements?.totalFloat) {
      // Parse the float value
      const floatStr = t.dataelements.totalFloat;
      totalFloat = parseFloat(floatStr) || 0;
    }

    const title =
      (t.dataelements && (t.dataelements.title || t.dataelements.name)) ||
      t.title ||
      "";
    const subtitle = t.type || (t.dataelements && t.dataelements.nlsType) || "";
    const status =
      (t.dataelements && (t.dataelements.status || t.dataelements.status)) ||
      "";

    const maturity =
      t.status || // <-- ENOVIA CSV export ka real state
      t.currentState || // <-- Some APIs send this
      t.dataelements?.currentState ||
      t.dataelements?.state ||
      t.dataelements?.Maturity ||
      "";

    const assignees = Array.isArray(t.relateddata?.assignees)
      ? t.relateddata.assignees
          .map((a) => a.dataelements?.fullname || "")
          .filter(Boolean)
      : [];

    // const assignee =
    //   t.relateddata?.assignees?.[0]?.dataelements?.fullname || "";

    // modify: detect children from all possible structures
    const childrenArr = getChildrenArray(t);

    // modify: build childrenIds array safely
    const childrenIds = childrenArr.map((c) => {
      const cid = getId(c);
      if (cid) return cid;

      // modify: fallback temporary ID
      const temp = Math.random().toString(36).slice(2, 9);
      c.__tempId = temp;
      return temp;
    });

    const node = {
      id,
      title,
      subtitle,
      status,
      maturity,
      assignees,
      dueDate: formateDate(t.dataelements?.dueDate || ""),
      startDate: formateDate(t.dataelements?.estimatedStartDate || ""),
      width: 220,
      height: 110,
      raw: t,
      totalFloat: totalFloat,
      // modify: ADD mandatory hierarchy fields
      parentId, // modify
      childrenIds, // modify
      hasChildren: childrenIds.length > 0, // modify
    };

    nodes.push(node);
    nodeById[id] = node;

    if (parentId) {
      edges.push({ from: parentId, to: id, type: "hierarchy" });
    }

    // predecessor edges
    if (Array.isArray(t.relateddata?.predecessors)) {
      t.relateddata.predecessors.forEach((pred) => {
        const pid = getId(pred);
        if (pid) edges.push({ from: pid, to: id, type: "dependency" });
      });
    }

    // modify: recursive walk into children
    childrenArr.forEach((child) => walk(child, id));
  };

  // modify: top-level tasks must have parentId = null
  tasks.forEach((task) => walk(task, null));

  // dedupe edges
  const seen = new Set();
  const uniqueEdges = [];
  edges.forEach((e) => {
    const key = `${e.from}=>${e.to}#${e.type}`;
    if (!seen.has(key)) {
      seen.add(key);
      uniqueEdges.push(e);
    }
  });

  return { nodes, edges: uniqueEdges, nodeById };
}
