// src/utility/hierarchyChainHelpers.js

/**
 * Computes the complete hierarchy chain for a node (ancestors + descendants)
 * @param {string} nodeId - The target node ID
 * @param {Object} nodeMap - Map of all nodes by ID
 * @returns {Object} chainNodeIds and chainEdgeIds Sets
 */
export function computeHierarchyChain(nodeId, nodeMap) {
  if (!nodeMap || !nodeId) {
    return { chainNodeIds: new Set(), chainEdgeIds: new Set() };
  }
  
  const chainNodeIds = new Set();
  const chainEdgeIds = new Set();
  
  // Helper: Find all descendants (children, grandchildren, etc.)
  const collectDescendants = (currentId) => {
    chainNodeIds.add(currentId);
    
    // Find all children in the node map
    const children = Object.values(nodeMap).filter(
      n => n.parentId === currentId
    );
    
    children.forEach(child => {
      chainNodeIds.add(child.id);
      chainEdgeIds.add(`${currentId}=>${child.id}#hierarchy`);
      collectDescendants(child.id);
    });
  };
  

  
  // Start from the target node
  chainNodeIds.add(nodeId);
  
  // Get ancestors
  // collectAncestors(nodeId);
  
  // Get descendants
  collectDescendants(nodeId);
  
  return { chainNodeIds, chainEdgeIds };
}

/**
 * Checks if an edge is in the highlighted chain
 * @param {Object} edge - The edge object
 * @param {Set} chainEdgeIds - Set of chain edge keys
 * @returns {boolean}
 */
export function isEdgeInChain(edge, chainEdgeIds) {
  if (!edge || !chainEdgeIds) return false;
  const edgeKey = `${edge.from}=>${edge.to}#${edge.type}`;
  return chainEdgeIds.has(edgeKey);
}

/**
 * Checks if a node is in the highlighted chain
 * @param {string} nodeId - Node ID to check
 * @param {Set} chainNodeIds - Set of chain node IDs
 * @returns {boolean}
 */
export function isNodeInChain(nodeId, chainNodeIds) {
  return chainNodeIds && chainNodeIds.has(nodeId);
}