import React, { useState, useRef, useEffect, useMemo } from "react";
import { createPortal } from "react-dom";
import ArticleIcon from "@mui/icons-material/Article";
import ArrowDropDownIcon from "@mui/icons-material/ArrowDropDown";
import CheckCircleIcon from "@mui/icons-material/CheckCircle";
import PersonIcon from "@mui/icons-material/Person";
import WarningIcon from "@mui/icons-material/Warning";
import HourglassEmptyIcon from "@mui/icons-material/HourglassEmpty";
import AutorenewIcon from "@mui/icons-material/Autorenew";
import AssignmentIcon from "@mui/icons-material/Assignment";
import CheckCircleOutlineIcon from "@mui/icons-material/CheckCircleOutline";
import FlagIcon from "@mui/icons-material/Flag";
import AddIcon from "@mui/icons-material/Add";
import RemoveIcon from "@mui/icons-material/Remove";
import GroupIcon from "@mui/icons-material/Group";
import initApp, { Space3DURL } from "../../utility/initApp.js";
import LayersIcon from "@mui/icons-material/Layers";

// Global variable to track the currently open dropdown
let globalOpenDropdownId = null;
let globalDropdownListeners = new Set();

// Function to notify all components that dropdown state changed
const notifyDropdownChange = () => {
  globalDropdownListeners.forEach(listener => listener());
};

// Function to open a dropdown
const openGlobalDropdown = (id) => {
  // Close previously opened dropdown
  if (globalOpenDropdownId && globalOpenDropdownId !== id) {
    globalOpenDropdownId = null;
    notifyDropdownChange();
  }
  
  globalOpenDropdownId = id;
  notifyDropdownChange();
};

// Function to close a dropdown
const closeGlobalDropdown = (id) => {
  if (globalOpenDropdownId === id) {
    globalOpenDropdownId = null;
    notifyDropdownChange();
  }
};

// Function to check if a dropdown is open
const isGlobalDropdownOpen = (id) => {
  return globalOpenDropdownId === id;
};

const getInitials = (name) => {
  if (!name) return "";
  const parts = name.trim().split(" ");
  const first = parts[0]?.charAt(0).toUpperCase() || "";
  const last =
    parts.length > 1 ? parts[parts.length - 1].charAt(0).toUpperCase() : "";
  return first + last;
};
const getLevelColor = (level) => {
  if (level === 0) return "#FFFFFF"; // Parent node always white

  const hue = (level * 40) % 360; // Slight hue shift per level
  const saturation = 40 + ((level * 3) % 15); // Slightly higher saturation
  const lightness = 92 - ((level * 1.5) % 6); // Slightly less light

  return `hsl(${hue}, ${saturation}%, ${lightness}%)`;
};
const calculateTooltipSize = (text, fontSize = 12, padding = 10) => {
  const canvas = document.createElement("canvas");
  const context = canvas.getContext("2d");
  context.font = `${fontSize}px Arial`;
  const lines = text.split("\n");
  const maxWidth = Math.max(
    ...lines.map((line) => context.measureText(line).width)
  );
  const height = lines.length * (fontSize + 4);
  return { width: maxWidth + padding * 2, height: height + padding * 2 };
};

const RectangleNode = ({
  id,
  x,
  y,
  width = 160,
  height = 65,
  title = "",
  subtitle = "",
  startDate,
  dueDate,
  assignees: d = [],
  maturity = "", // Changed from status to maturity
  maturityDescription = "",
  status = "",
  statusDescription = "",
  containerRef,
  description = "",
  dragNode,
  hasChildren = false,
  isExpanded = false,
  onDoubleClick = null,
  onMouseDown,
  isInitial = false,
  hierarchyDepth = 0,
  objectId,
  totalFloat = 0,
  showCriticalPath = false,
  isInChain = false,
  onHighlightChain = null,
  opacity = 1,
  loading = false,
  forceResetHover = false, // NEW PROP to force hover reset
}) => {
  // Safe status check
  const safeStatus = (status || "").toLowerCase().trim();
  const showWarningIcon =
    safeStatus === "late" || safeStatus === "delay" || safeStatus === "delayed";
  const nodeRef = useRef(null);
  const dropdownRef = useRef(null);
  const [hoverIndex, setHoverIndex] = useState(null);
  const [tooltip, setTooltip] = useState({
    visible: false,
    text: "",
    textNode: null,
    width: 0,
    height: 0,
    x: 0,
    y: 0,
  });
  const ENOVIA_BASE_URL = Space3DURL;

  // Local state to track if this dropdown is open (using global state)
  const [isThisDropdownOpen, setIsThisDropdownOpen] = useState(false);

  // Effect to sync with global dropdown state
  useEffect(() => {
    const updateLocalState = () => {
      setIsThisDropdownOpen(isGlobalDropdownOpen(id));
    };
    
    // Initial sync
    updateLocalState();
    
    // Subscribe to global changes
    globalDropdownListeners.add(updateLocalState);
    
    // Cleanup
    return () => {
      globalDropdownListeners.delete(updateLocalState);
    };
  }, [id]);

  const showLocalTooltip = (tooltipString, tooltipNode) => {
    const { width: tw, height: th } = calculateTooltipSize(tooltipString);
    setTooltip({
      visible: true,
      text: tooltipString,
      textNode: tooltipNode,
      width: tw,
      height: th,
      x: width - tw - 8,
      y: height + 8,
    });
  };

  const maturityIcon = (() => {
    const s = String(maturity).toLowerCase().trim();

    if (s.includes("late") || s.includes("delay")) {
      return <WarningIcon style={{ fontSize: 16, color: "#D9534F" }} />;
    }

    return null; // no icon for others
  })();

  const hideLocalTooltip = () => {
    setTooltip((t) => ({ ...t, visible: false }));
  };

  const [highlighted, setHighlighted] = useState(false);
  const [currentStatus, setCurrentStatus] = useState(status);
  const [menuPos, setMenuPos] = useState({ top: 0, left: 0 });

  // ==================== CRITICAL FIX: Hover Reset Logic ====================

  // Effect 1: Reset hover when chain status changes
  useEffect(() => {
    setHighlighted(false);
    hideLocalTooltip();
  }, [isInChain]);

  // Effect 2: Reset hover when forceResetHover prop changes
  useEffect(() => {
    if (forceResetHover) {
      setHighlighted(false);
      hideLocalTooltip();
    }
  }, [forceResetHover]);

  // Effect 3: Reset hover when menu opens
  useEffect(() => {
    if (isThisDropdownOpen) {
      setHighlighted(false);
      hideLocalTooltip();
    }
  }, [isThisDropdownOpen]);

  // Effect 4: Reset hover when component unmounts (moving between layers)
  useEffect(() => {
    return () => {
      setHighlighted(false);
      hideLocalTooltip();
    };
  }, []);

  const isCritical = showCriticalPath && totalFloat === 0;
  
  // ==================== Memoized Stroke Color ====================
  const rectStroke = useMemo(() => {
    // Hover / highlight should slightly brighten, not override meaning
    if (highlighted && isInChain) return "#3B82F6"; // brighter blue
    if (highlighted && isCritical) return "#EF4444"; // brighter red

    // Base semantic colors
    if (isInChain) return "#1A73E8"; // chain blue
    if (isCritical) return "#CC0000"; // critical red

    // Default
    return highlighted ? "#4285F4" : "#1b1b17";
  }, [highlighted, isInChain, isCritical]);

  // ==================== Other Effects ====================
  useEffect(() => {
    setCurrentStatus(status);
  }, [status]);

  const handleMenuClick = () => {
    const taskId = objectId || id;
    if (!taskId) {
      console.error("Object ID missing");
      return;
    }
    const url = `${ENOVIA_BASE_URL}/common/emxNavigator.jsp?isPopup=false&objectId=${taskId}`;
    window.open(url, "_blank");
  };

  const padding = 10;
  const iconSize = 18;
  const spacing = 10;
  const statusWidth = 70;
  const statusHeight = 28;
  const titleX = padding + iconSize + 6;
  const titleY = padding + 16;
  const subtitleY = padding + 38;
  const rowY = padding + 60;
  const assigneeList = Array.isArray(d)
    ? d.filter((n) => n && n.trim())
    : d && d.trim()
    ? [d]
    : [];
  const hasAssignee = assigneeList.length > 0;
  const assigneeColor = hasAssignee ? "#075985" : "#B0B0B0";
  const assigneeInitials = hasAssignee ? getInitials(assigneeList[0]) : "";
  const isMultipleAssignees = assigneeList.length > 1;

  const getMaturityDisplay = (m) => {
    if (!m) return "No Status";
    const s = String(m).toLowerCase().trim();

    if (s === "late") return "Late";
    if (s === "delay" || s === "delayed") return "Delayed";
    if (s === "active") return "In Work";
    if (s === "create") return "Draft";
    if (s === "assign") return "To Do";

    if (s.includes("to do") || s.includes("todo")) return "To Do";
    if (s.includes("in work") || s.includes("in-work") || s === "inwork")
      return "In Work";
    if (s.includes("draft")) return "Draft";
    if (s.includes("in progress") || s.includes("inprogress"))
      return "In Progress";
    if (s.includes("review") || s.includes("in review")) return "In Review";
    if (s.includes("complete") || s.includes("completed") || s.includes("done"))
      return "Completed";
    if (s.includes("release") || s.includes("released")) return "Released";
    if (s.includes("late") || s.includes("delayed")) return "Delayed";

    // Capitalize first letter of each word as fallback
    return m
      .split(" ")
      .map((word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
      .join(" ");
  };
  
  const getMaturityColor = (m) => {
    if (!m) return "rgb(110,110,110)"; // fallback muted grey

    const s = String(m).toLowerCase().trim();
    if (
      s === "active" ||
      s.includes("in work") ||
      s.includes("in-work") ||
      s.includes("inwork") ||
      s.includes("in progress")
    ) {
      return "rgb(204,160,30)"; // muted mustard yellow
    }
    if (s === "create" || s.includes("draft")) {
      return "rgb(120,120,120)"; // professional muted grey
    }

    if (s === "assign" || s.includes("to do") || s.includes("todo")) {
      return "rgb(110,110,110)"; // muted deep blue
    }
    if (s.includes("review")) {
      return "rgb(70,65,125)"; // muted indigo
    }
    if (s.includes("complete") || s.includes("done")) {
      return "rgba(11, 139, 21, 1)"; // muted teal
    }
    if (s.includes("release")) {
      return "rgba(37, 165, 224, 1)"; // muted slate blue
    }

    if (s.includes("late") || s.includes("delay")) {
      return "rgba(150, 59, 59, 1)"; // muted red
    }

    return "rgb(110,110,110)";
  };

  const displayMaturity = getMaturityDisplay(maturity);
  const maturityColor = getMaturityColor(maturity);

  const subtitleIconMap = {
    "Pending Approval": (
      <HourglassEmptyIcon style={{ fontSize: iconSize, color: "#F28C38" }} />
    ),
    Phase: <AutorenewIcon style={{ fontSize: iconSize, color: "#234A96" }} />,
    Milestone: <FlagIcon style={{ fontSize: iconSize, color: "#2E7D32" }} />,
    Completed: (
      <CheckCircleIcon style={{ fontSize: iconSize, color: "#2E7D32" }} />
    ),
    Task: <AssignmentIcon style={{ fontSize: iconSize, color: "#707070" }} />,
    Late: <WarningIcon style={{ fontSize: iconSize, color: "#D9534F" }} />,
    Delayed: <WarningIcon style={{ fontSize: iconSize, color: "#D9534F" }} />,
  };

  const subtitleIcon = subtitleIconMap[subtitle] || (
    <HourglassEmptyIcon style={{ fontSize: iconSize, color: "#707070" }} />
  );

  const levelColors = {
    0: "#FFFFFF",
    1: "#F2F7FF",
    2: "#EAF5EA",
    3: "#FFF7E5",
    4: "#FDECEC",
    5: "#F4F1FF",
  };

  const openMenu = (e) => {
    e.stopPropagation();
    e.preventDefault();
    hideLocalTooltip();
    
    // Use global function to open this dropdown
    openGlobalDropdown(id);

    if (dropdownRef.current) {
      const rect = dropdownRef.current.getBoundingClientRect();
      setMenuPos({
        top: rect.bottom + 4,
        left: rect.right - 150,
      });
    }
  };

  const closeMenu = () => {
    // Use global function to close this dropdown
    closeGlobalDropdown(id);
  };

  // Effect to handle click outside
  useEffect(() => {
    const handleClickOutside = (event) => {
      // Check if click is outside the dropdown
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        // Also check if the click is not on the dropdown menu itself
        const dropdownMenu = document.querySelector('[data-dropdown-menu]');
        if (dropdownMenu && !dropdownMenu.contains(event.target)) {
          closeMenu();
        }
      }
    };

    if (isThisDropdownOpen) {
      document.addEventListener("mousedown", handleClickOutside);
    } else {
      document.removeEventListener("mousedown", handleClickOutside);
    }

    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [isThisDropdownOpen]);

  const handleMouseEnter = () => {
    // Don't set hover if in chain (chain nodes should not show hover effect)
    if (!isInChain) {
      setHighlighted(true);
    }

    const displayAssignee = hasAssignee
      ? assigneeList.join(", ")
      : "No Assignee";
    const tooltipString =
      `Title: ${title}\n` +
      `Type: ${subtitle}\n` +
      `Estimated Start Date: ${startDate || "—"}\n` +
      `Due Date: ${dueDate || "—"}\n` +
      `Assignee: ${displayAssignee}\n` +
      `Maturity:${displayMaturity}`;

    const tooltipNode = (
      <>
        <strong>Title:</strong> {title} <br />
        <strong>Type:</strong> {subtitle} <br />
        <strong>Estimated Start Date:</strong> {startDate || "—"} <br />
        <strong>Due Date:</strong> {dueDate || "—"} <br />
        <strong>{isMultipleAssignees ? "Assignees:" : "Assignee:"}</strong>{" "}
        {hasAssignee ? assigneeList.join(", ") : "No Assignee"} <br />
        <strong>Maturity:</strong> {displayMaturity} <br />
        {maturityDescription && (
          <>
            {maturityDescription}
            <br />
          </>
        )}
        {description && <>{description}</>}
      </>
    );
    showLocalTooltip(tooltipString, tooltipNode);
  };

  const handleMouseMove = () => {
    if (!tooltip.visible && !isInChain) {
      setHighlighted(true);

      const displayAssignee = hasAssignee
        ? assigneeList.join(", ")
        : "No Assignee";
      const tooltipString =
        `Title: ${title}\n` +
        `Type: ${subtitle}\n` +
        `Estimated Start Date: ${startDate || "—"}\n` +
        `Due Date: ${dueDate || "—"}\n` +
        `Assignee: ${displayAssignee}\n` +
        `Maturity:${displayMaturity}`;

      const tooltipNode = (
        <>
          <strong>Title:</strong> {title} <br />
          <strong>Type:</strong> {subtitle} <br />
          <strong>Estimated Start Date:</strong> {startDate || "—"} <br />
          <strong>Due Date:</strong> {dueDate || "—"} <br />
          <strong>
            {isMultipleAssignees ? "Assignees:" : "Assignee:"}
          </strong>{" "}
          {hasAssignee ? assigneeList.join(", ") : "No Assignee"} <br />
          <strong>Maturity:</strong> {displayMaturity} <br />
          {maturityDescription && (
            <>
              {maturityDescription}
              <br />
            </>
          )}
          {description && <>{description}</>}
        </>
      );

      showLocalTooltip(tooltipString, tooltipNode);
    }
  };

  const handleMouseLeave = () => {
    setHighlighted(false);
    hideLocalTooltip();
  };

  return (
    <g
      ref={nodeRef}
      transform={`translate(${x}, ${y})`}
      opacity={opacity}
      onMouseDown={(e) => onMouseDown && onMouseDown(e)}
      onDoubleClick={(e) => {
        e.stopPropagation();
        if (onDoubleClick) onDoubleClick();
      }}
      onMouseEnter={() => {
        setHighlighted(true);
        const displayAssignee = hasAssignee
          ? assigneeList.join(", ")
          : "No Assignee";
        const tooltipString =
          `Title: ${title}\n` +
          `Type: ${subtitle}\n` +
          `Estimated Start Date: ${startDate || "—"}\n` +
          `Due Date: ${dueDate || "—"}\n` +
          `Assignee: ${displayAssignee}\n` +
          `Maturity: ${displayMaturity || "—"}`; // UPDATED: Show maturity instead of status

        // React node for tooltip rendering with bold headers
        const tooltipNode = (
          <>
            <strong>Title:</strong> {title} <br />
            <strong>Type:</strong> {subtitle} <br />
            <strong>Estimated Start Date:</strong> {startDate || "—"} <br />
            <strong>Due Date:</strong> {dueDate || "—"} <br />
            <strong>
              {isMultipleAssignees ? "Assignees:" : "Assignee:"}
            </strong>{" "}
            {hasAssignee ? assigneeList.join(", ") : "No Assignee"} <br />
            <strong>Maturity:</strong> {displayMaturity || "—"} <br />{" "}
            {/* UPDATED */}
            {maturityDescription && (
              <>
                <strong>Maturity Description:</strong> {maturityDescription}
                <br />
              </>
            )}
            {description && (
              <>
                <strong>Description:</strong> {description}
              </>
            )}
          </>
        );
        showLocalTooltip(tooltipString, tooltipNode);
      }}
      onMouseMove={() => {
        if (!tooltip.visible) {
          setHighlighted(true);
          const displayAssignee = hasAssignee
            ? assigneeList.join(", ")
            : "No Assignee";
          const tooltipString =
            `Title: ${title}\n` +
            `Type: ${subtitle}\n` +
            `Estimated Start Date: ${startDate || "—"}\n` +
            `Due Date: ${dueDate || "—"}\n` +
            `Assignee: ${displayAssignee}\n` +
            `Maturity: ${displayMaturity || "—"}`; // UPDATED: Show maturity instead of status

          const tooltipNode = (
            <>
              <strong>Title:</strong> {title} <br />
              <strong>Type:</strong> {subtitle} <br />
              <strong>Estimated Start Date:</strong> {startDate || "—"} <br />
              <strong>Due Date:</strong> {dueDate || "—"} <br />
              <strong>
                {isMultipleAssignees ? "Assignees:" : "Assignee:"}
              </strong>{" "}
              {hasAssignee ? assigneeList.join(", ") : "No Assignee"} <br />
              <strong>Maturity:</strong> {displayMaturity || "—"} <br />{" "}
              {/* UPDATED */}
              {maturityDescription && (
                <>
                  <strong>Maturity Description:</strong> {maturityDescription}
                  <br />
                </>
              )}
              {description && (
                <>
                  <strong>Description:</strong> {description}
                </>
              )}
            </>
          );

          showLocalTooltip(tooltipString, tooltipNode);
        }
      }}
      onMouseLeave={() => {
        setHighlighted(false);
        hideLocalTooltip();
      }}
      style={{
        cursor: dragNode === id ? "grabbing" : "grab",
        userSelect: "none",
      }}
    >
      <rect
        width={width}
        height={height}
        rx={6}
        ry={6}
        fill={getLevelColor(hierarchyDepth)}
        stroke={rectStroke}
        strokeWidth={isInChain || isCritical ? 3 : 1}
        filter={
          isInChain && isCritical
            ? "url(#chainNodeElevation)" // no red glow by default
            : isInChain
            ? "url(#chainNodeElevation)"
            : isCritical && highlighted
            ? "url(#criticalNodeGlow)" // glow ONLY on hover
            : highlighted
            ? "url(#nodeHover)"
            : "none"
        }
        style={{
          transition:
            highlighted && !isInChain
              ? "filter 0.3s ease, stroke-width 0.3s ease"
              : "none",
        }}
      />

      <foreignObject x={padding} y={titleY - 16} width={16} height={16}>
        <ArticleIcon style={{ fontSize: 18, color: "#234A96" }} />
      </foreignObject>

      <foreignObject
        x={titleX}
        y={titleY - 16}
        width={width - titleX - 30}
        height={35}
      >
        <div
          xmlns="http://www.w3.org/1999/xhtml"
          style={{
            color: "#234A96",
            fontWeight: 600,
            textAlign: "left",
            whiteSpace: "nowrap",
            overflow: "hidden",
            textOverflow: "ellipsis",
            fontSize: "14px",
            lineHeight: "1.4",
          }}
        >
          {title}
        </div>
      </foreignObject>

      {/* Dropdown */}
      <g
        ref={dropdownRef}
        transform={`translate(${width - 28}, 10)`}
        onClick={(e) => {
          e.stopPropagation();
          if (isThisDropdownOpen) closeMenu();
          else openMenu(e);
        }}
        style={{ cursor: "pointer" }}
      >
        <foreignObject width={20} height={20}>
          <ArrowDropDownIcon style={{ fontSize: 20, color: "#5A5A5A" }} />
        </foreignObject>
      </g>

      {/* Expand / Collapse Toggle */}
      {hasChildren && (
        <g
          transform={`translate(${width - 9}, -6)`}
          onClick={onDoubleClick}
          style={{ cursor: "pointer" }}
        >
          <rect
            width="20"
            height="20"
            rx="4"
            ry="4"
            fill="#eee"
            stroke="#666"
            strokeWidth="1"
          />

          <foreignObject x="2" y="2" width="16" height="16">
            {isExpanded ? (
              <RemoveIcon
                style={{
                  fontSize: 16,
                  color: "#555",
                  width: "16px",
                  height: "16px",
                }}
              />
            ) : (
              <AddIcon
                style={{
                  fontSize: 16,
                  color: "#555",
                  width: "16px",
                  height: "16px",
                }}
              />
            )}
          </foreignObject>
        </g>
      )}

      {/* Dropdown Menu */}
      {isThisDropdownOpen &&
        dropdownRef.current &&
        createPortal(
          (() => {
            const rect = dropdownRef.current.getBoundingClientRect();
             const taskId = objectId || id;

            return (
              <div
                data-dropdown-menu // Added data attribute for click detection
                style={{
                  position: "fixed",
                  top: rect.top,
                  left: rect.right + 16,
                  width: 150,
                  background: "white",
                  border: "1px solid #C8C6B8",
                  borderRadius: "4px",
                  fontSize: "12px",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.35)",
                  fontFamily: "Arial",
                  padding: "4px",
                  zIndex: 999999999,
                  pointerEvents: "auto",
                }}
                onClick={(e) => e.stopPropagation()}
              >
                <div
                  style={{
                    padding: 8,
                    display: "flex",
                    alignItems: "center",
                    cursor: "pointer",
                    backgroundColor:
                      hoverIndex === 0 ? "#bbb8b88a" : "transparent",
                    borderRadius: 4,
                    transition: "background 0.2s ease",
                    borderBottom: "1px solid #ccc",
                  }}
                  onMouseEnter={() => setHoverIndex(0)}
                  onMouseLeave={() => setHoverIndex(null)}
                  onClick={(e) => {
                    e.stopPropagation();
                    window.open(
                      `${ENOVIA_BASE_URL}/common/emxNavigator.jsp?isPopup=false&objectId=${taskId}`,
                      "_blank"
                    );
                  }}
                >
                  <CheckCircleOutlineIcon
                    style={{ fontSize: 16, marginRight: 6 }}
                  />
                  Open
                </div>

                {/* Chain Option */}
                {(hasChildren || isInChain) && (
                  <div
                    style={{
                      padding: 8,
                      display: "flex",
                      alignItems: "center",
                      cursor: "pointer",
                      backgroundColor:
                        hoverIndex === 3 ? "#bbb8b88a" : "transparent",
                      borderRadius: 4,
                      borderBottom: "1px solid #ccc",
                      transition: "background 0.2s ease",
                    }}
                    onMouseEnter={() => setHoverIndex(3)}
                    onMouseLeave={() => setHoverIndex(null)}
                    onClick={(e) => {
                      e.stopPropagation();
                      e.preventDefault();
                      if (onHighlightChain) {
                        // When already in chain (clicking "Lower Chain to Background")
                        // Pass nodeId and isClearingChain = true
                        if (isInChain) {
                          onHighlightChain(id, true); // isClearingChain = true
                        } else {
                          onHighlightChain(id, false); // isClearingChain = false
                        }
                      }
                      closeMenu();
                    }}
                  >
                    <LayersIcon
                      style={{
                        fontSize: 16,
                        marginRight: 6,
                        color: isInChain ? "#1A73E8" : "#234A96",
                      }}
                    />
                    {isInChain ? "Exit Layered View" : "Show Layered View"}
                  </div>
                )}

                <div
                  style={{
                    padding: 8,
                    display: "flex",
                    alignItems: "center",
                    cursor: "pointer",
                    backgroundColor:
                      hoverIndex === 1 ? "#bbb8b88a" : "transparent",
                    borderRadius: 4,
                    transition: "background 0.2s ease",
                    borderBottom: "1px solid #ccc",
                  }}
                  onMouseEnter={() => setHoverIndex(1)}
                  onMouseLeave={() => setHoverIndex(null)}
                  onClick={(e) => {
                    e.stopPropagation();
                    window.open(
                      `${ENOVIA_BASE_URL}/common/emxNavigator.jsp?isPopup=false&objectId=${taskId}`,
                      "_blank"
                    );
                  }}
                >
                  <PersonIcon style={{ fontSize: 16, marginRight: 6 }} />
                  Change Assignee
                </div>

                <div
                  style={{
                    padding: 8,
                    display: "flex",
                    alignItems: "center",
                    cursor: "pointer",
                    backgroundColor:
                      hoverIndex === 2 ? "#bbb8b88a" : "transparent",
                    borderRadius: 4,
                    transition: "background 0.2s ease",
                  }}
                  onMouseEnter={() => setHoverIndex(2)}
                  onMouseLeave={() => setHoverIndex(null)}
                  onClick={(e) => {
                    e.stopPropagation();
                    window.open(
                      `${ENOVIA_BASE_URL}/common/emxNavigator.jsp?isPopup=false&objectId=${taskId}`,
                      "_blank"
                    );
                  }}
                >
                  <CheckCircleIcon style={{ fontSize: 16, marginRight: 6 }} />
                  Mark as Complete
                </div>
              </div>
            );
          })(),
          document.body
        )}

      {/* Subtitle icon */}
      <foreignObject
        x={padding}
        y={subtitleY - iconSize / 2 - 4}
        width={iconSize}
        height={iconSize}
      >
        <div
          xmlns="http://www.w3.org/1999/xhtml"
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            width: "100%",
            height: "100%",
          }}
        >
          {subtitleIcon}
        </div>
      </foreignObject>

      <text x={titleX} y={subtitleY - 2} fontSize="12" fill="#0f0e0eff">
        {subtitle}
      </text>

      {/* Bottom Row */}
      <g transform={`translate(${padding}, ${rowY})`}>
        {showWarningIcon && (
          <foreignObject
            x={0}
            y={-11}
            width={iconSize}
            height={iconSize}
            onMouseEnter={() => {
              const tooltipString = `Status: ${"Late" || "—"}`;
              const tooltipNode = (
                <>
                  <strong>Status:</strong> {"Late" || "—"}
                </>
              );
              showLocalTooltip(tooltipString, tooltipNode);
            }}
            onMouseLeave={hideLocalTooltip}
          >
            <div
              xmlns="http://www.w3.org/1999/xhtml"
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                width: "100%",
                height: "100%",
              }}
            >
              <WarningIcon style={{ fontSize: iconSize, color: "#D9534F" }} />
            </div>
          </foreignObject>
        )}

        <text x={iconSize + 6} y={5} fontSize="12" fill="#333">
          {dueDate}
        </text>

        {/* Assignee circle */}
        <g
          transform={`translate(${iconSize + spacing + 86},${
            iconSize / 4 - 6
          })`}
          onMouseEnter={() => {
            const displayAssignee =
              Array.isArray(d) && d.length > 0
                ? d.join(", ")
                : d && typeof d === "string" && d.trim()
                ? d
                : "No Assignee";
            const tooltipNode = (
              <>
                <strong>Assignee:</strong> {displayAssignee}
              </>
            );
            showLocalTooltip(`Assignee: ${displayAssignee}`, tooltipNode);
          }}
          onMouseLeave={hideLocalTooltip}
        >
          {isMultipleAssignees ? (
            <foreignObject
              x={-iconSize / 2 - 4}
              y={-iconSize / 2 - 6}
              width={iconSize + 8}
              height={iconSize + 8}
            >
              <div
                xmlns="http://www.w3.org/1999/xhtml"
                style={{
                  width: iconSize + 8,
                  height: iconSize + 8,
                  borderRadius: "50%",
                  backgroundColor: "#075985",
                  display: "flex",
                  justifyContent: "center",
                  alignItems: "center",
                }}
              >
                <GroupIcon style={{ fontSize: iconSize, color: "#fff" }} />
              </div>
            </foreignObject>
          ) : (
            <>
              <circle r={iconSize / 2 + 4} fill={assigneeColor} />
              {assigneeInitials && (
                <text
                  x="0"
                  y="4"
                  fontSize="13"
                  textAnchor="middle"
                  fill="white"
                  fontWeight="600"
                >
                  {assigneeInitials}
                </text>
              )}
            </>
          )}
        </g>

        {/* Status pill - Now showing Maturity */}
        <g
          transform={`translate(${
            iconSize + spacing + 80 + iconSize + spacing
          }, ${-iconSize / 2 - 10})`}
          onMouseEnter={() => {
            const tooltipString = `Maturity: ${displayMaturity || "—"}\n${
              maturityDescription || ""
            }`;
            const tooltipNode = (
              <>
                <strong>Maturity:</strong> {displayMaturity || "—"} <br />
                {maturityDescription && (
                  <>
                    <strong>Maturity Description:</strong> {maturityDescription}
                    <br />
                  </>
                )}
              </>
            );
            showLocalTooltip(tooltipString, tooltipNode);
          }}
          onMouseLeave={hideLocalTooltip}
        >
          <rect
            width={statusWidth}
            height={statusHeight}
            rx={10}
            fill={maturityColor}
          />
          <foreignObject x="0" y="0" width={statusWidth} height={statusHeight}>
            <div
              xmlns="http://www.w3.org/1999/xhtml"
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                width: "100%",
                height: "100%",
                color: "white",
                fontSize: "10px",
                fontWeight: "600",
                textAlign: "center",
                lineHeight: "1.2",
                padding: "2px",
                boxSizing: "border-box",
                wordBreak: "break-word",
              }}
            >
              {maturityIcon}
              {displayMaturity}
            </div>
          </foreignObject>
        </g>
      </g>

      {/* Tooltip */}
      {!isThisDropdownOpen &&
        tooltip.visible &&
        createPortal(
          (() => {
            const nodeRect = nodeRef.current?.getBoundingClientRect() || {
              top: 0,
              left: 0,
            };
            return (
              <div
                style={{
                  position: "fixed",
                  top: nodeRect.bottom + 4,
                  left: nodeRect.right - tooltip.width,
                  minWidth: tooltip.width,
                  background: "white",
                  border: "1px solid #363a3fff",
                  borderRadius: "8px",
                  padding: "8px",
                  fontSize: "12px",
                  color: "#202124",
                  whiteSpace: "pre-line",
                  boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
                  pointerEvents: "none",
                  zIndex: 999999999,
                  lineHeight: "1.6",
                }}
              >
                {tooltip.textNode}
              </div>
            );
          })(),
          document.body
        )}
    </g>
  );
};

export default RectangleNode;